export type Declaration = VariableDeclaration | ParameterDeclaration | BindingElement | MissingDeclaration | FunctionDeclaration | ClassDeclaration | ClassExpression | InterfaceDeclaration | TypeAliasDeclaration | EnumMember | EnumDeclaration | ImportDeclaration | NamespaceImport | ExportAssignment | NamespaceExportDeclaration | NamespaceExport | ExportSpecifier | CallSignatureDeclaration | ConstructSignatureDeclaration | ConstructorDeclaration | GetAccessorDeclaration | SetAccessorDeclaration | IndexSignatureDeclaration | MethodSignatureDeclaration | MethodDeclaration | PropertySignatureDeclaration | PropertyDeclaration | SemicolonClassElement | ClassStaticBlockDeclaration | NoSubstitutionTemplateLiteral | BinaryExpression | ArrowFunction | FunctionExpression | CallExpression | ObjectLiteralExpression | SpreadAssignment | PropertyAssignment | ShorthandPropertyAssignment | MappedTypeNode | TypeLiteralNode | NamedTupleMember | FunctionTypeNode | ConstructorTypeNode | JsxAttributes | JsxAttribute | JSDocSignature | ModuleDeclaration | ImportEqualsDeclaration | ExportDeclaration | ImportClause | ImportSpecifier | TypeParameterDeclaration | JSDocTypeLiteral;
export type ClassElement = ConstructorDeclaration | GetAccessorDeclaration | SetAccessorDeclaration | IndexSignatureDeclaration | MethodDeclaration | PropertyDeclaration | SemicolonClassElement | ClassStaticBlockDeclaration;
export type TypeElement = NotEmittedTypeElement | CallSignatureDeclaration | ConstructSignatureDeclaration | GetAccessorDeclaration | SetAccessorDeclaration | IndexSignatureDeclaration | MethodSignatureDeclaration | PropertySignatureDeclaration;
export type ObjectLiteralElement = GetAccessorDeclaration | SetAccessorDeclaration | MethodDeclaration | SpreadAssignment | PropertyAssignment | ShorthandPropertyAssignment | JsxSpreadAttribute;
export type JSDocTag = JSDocTypeTag | JSDocUnknownTag | JSDocTemplateTag | JSDocReturnTag | JSDocPublicTag | JSDocPrivateTag | JSDocProtectedTag | JSDocReadonlyTag | JSDocOverrideTag | JSDocDeprecatedTag | JSDocSeeTag | JSDocImplementsTag | JSDocAugmentsTag | JSDocSatisfiesTag | JSDocThrowsTag | JSDocThisTag | JSDocImportTag | JSDocCallbackTag | JSDocOverloadTag | JSDocTypedefTag | JSDocParameterOrPropertyTag;
export type ArrayBindingElement = BindingElement | OmittedExpression;
export type AssertionExpression = TypeAssertion | AsExpression;
export type BooleanLiteral = TrueLiteral | FalseLiteral;
export type ConciseBody = Block | Expression;
export type DestructuringAssignment = ObjectDestructuringAssignment | ArrayDestructuringAssignment;
export type LiteralToken = NumericLiteral | BigIntLiteral | StringLiteral | JsxText | RegularExpressionLiteral | NoSubstitutionTemplateLiteral;
export type Modifier = AbstractKeyword | AccessorKeyword | AsyncKeyword | ConstKeyword | DeclareKeyword | DefaultKeyword | ExportKeyword | InKeyword | PrivateKeyword | ProtectedKeyword | PublicKeyword | ReadonlyKeyword | OutKeyword | OverrideKeyword | StaticKeyword;
export type ObjectLiteralElementLike = PropertyAssignment | ShorthandPropertyAssignment | SpreadAssignment | MethodDeclaration | GetAccessorDeclaration | SetAccessorDeclaration;
export type PropertyNameLiteral = Identifier | StringLiteral | NumericLiteral;
export type PseudoLiteralToken = TemplateHead | TemplateMiddle | TemplateTail;
export type TemplateLiteralToken = NoSubstitutionTemplateLiteral | PseudoLiteralToken;
export type ArrayDestructuringAssignment = BinaryExpression;
export type ObjectDestructuringAssignment = BinaryExpression;
export type FunctionBody = Block;
export type IncrementExpression = UpdateExpressionBase;

export interface ForInStatement extends StatementBase {
  readonly kind: Kind.ForInStatement;
  readonly awaitModifier?: AwaitKeyword;
  readonly initializer: ForInitializer;
  readonly expression: Expression;
  readonly statement: Statement;
}
export interface ForOfStatement extends StatementBase {
  readonly kind: Kind.ForOfStatement;
  readonly awaitModifier?: AwaitKeyword;
  readonly initializer: ForInitializer;
  readonly expression: Expression;
  readonly statement: Statement;
}
export interface CaseClause extends NodeBase {
  readonly kind: Kind.CaseClause;
  readonly expression: Expression;
  readonly statements: NodeArray<Statement>;
}
export interface DefaultClause extends NodeBase {
  readonly kind: Kind.DefaultClause;
  readonly expression: Expression;
  readonly statements: NodeArray<Statement>;
}
export interface ObjectBindingPattern extends NodeBase {
  readonly kind: Kind.ObjectBindingPattern;
  readonly elements: NodeArray<BindingElement>;
}
export interface ArrayBindingPattern extends NodeBase {
  readonly kind: Kind.ArrayBindingPattern;
  readonly elements: NodeArray<BindingElement>;
}
export interface JSDocParameterTag extends JSDocTagBase {
  readonly kind: Kind.JSDocParameterTag;
  readonly name: EntityName;
  readonly isBracketed: boolean;
  readonly typeExpression?: TypeNode;
  readonly isNameFirst: boolean;
}
export interface JSDocPropertyTag extends JSDocTagBase {
  readonly kind: Kind.JSDocPropertyTag;
  readonly name: EntityName;
  readonly isBracketed: boolean;
  readonly typeExpression?: TypeNode;
  readonly isNameFirst: boolean;
}
export type ForInOrOfStatement = ForInStatement | ForOfStatement;
export type CaseOrDefaultClause = CaseClause | DefaultClause;
export type BindingPattern = ObjectBindingPattern | ArrayBindingPattern;
export type JSDocParameterOrPropertyTag = JSDocParameterTag | JSDocPropertyTag;

